import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"騎砍2 | 王國管理深度指南：當國王比打仗難","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/kingdom-management.md","filePath":"bannerlord/kingdom-management.md"}'),l={name:"bannerlord/kingdom-management.md"};function h(o,t,i,n,b,s){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="騎砍2-王國管理深度指南-當國王比打仗難" tabindex="-1">騎砍2 | 王國管理深度指南：當國王比打仗難 <a class="header-anchor" href="#騎砍2-王國管理深度指南-當國王比打仗難" aria-label="Permalink to &quot;騎砍2 | 王國管理深度指南：當國王比打仗難&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>很多人以為打下城、建國就破關了。實際上，<strong>當國王比當傭兵難十倍</strong>。你要管領主心情、封地分配、政策投票、外交關係、經濟收支……一個沒弄好，王國就崩了。</p><hr><h2 id="一、王國界面導覽" tabindex="-1">一、王國界面導覽 <a class="header-anchor" href="#一、王國界面導覽" aria-label="Permalink to &quot;一、王國界面導覽&quot;">​</a></h2><p>打開王國介面（K鍵），你會看到：</p><table tabindex="0"><thead><tr><th>分頁</th><th>內容</th></tr></thead><tbody><tr><td>王國</td><td>王國總覽、外交狀態</td></tr><tr><td>封地</td><td>所有城鎮和城堡列表</td></tr><tr><td>領主</td><td>所有領主、他們的封地、關係值</td></tr><tr><td>政策</td><td>已頒布和可頒布的政策</td></tr><tr><td>軍團</td><td>當前活躍的軍團</td></tr></tbody></table><hr><h2 id="二、封地分配" tabindex="-1">二、封地分配 <a class="header-anchor" href="#二、封地分配" aria-label="Permalink to &quot;二、封地分配&quot;">​</a></h2><h3 id="_2-1-分配原則" tabindex="-1">2.1 分配原則 <a class="header-anchor" href="#_2-1-分配原則" aria-label="Permalink to &quot;2.1 分配原則&quot;">​</a></h3><p>這是最容易搞砸的環節。領主沒封地 = 不滿 = 叛變。</p><table tabindex="0"><thead><tr><th>原則</th><th>說明</th></tr></thead><tbody><tr><td>新領主先給一座</td><td>剛挖來的領主第一座城最重要</td></tr><tr><td>不要讓一人坐大</td><td>單一領主超過 3 座城 = 危險</td></tr><tr><td>自己保留核心城</td><td>首都 + 1-2 座經濟城自己留</td></tr><tr><td>邊境城給強領主</td><td>邊境容易被打，給兵多的領主</td></tr></tbody></table><h3 id="_2-2-分配投票" tabindex="-1">2.2 分配投票 <a class="header-anchor" href="#_2-2-分配投票" aria-label="Permalink to &quot;2.2 分配投票&quot;">​</a></h3><p>打下新城 → 王國投票決定歸誰。</p><ul><li>你可以提名任何人（包括自己）</li><li>你的一票權重最高（你是國王！）</li><li>領主投票看關係值和他們現有封地數量</li></ul><hr><h2 id="三、政策系統" tabindex="-1">三、政策系統 <a class="header-anchor" href="#三、政策系統" aria-label="Permalink to &quot;三、政策系統&quot;">​</a></h2><h3 id="_3-1-推薦政策" tabindex="-1">3.1 推薦政策 <a class="header-anchor" href="#_3-1-推薦政策" aria-label="Permalink to &quot;3.1 推薦政策&quot;">​</a></h3><table tabindex="0"><thead><tr><th>政策</th><th>效果</th><th style="text-align:center;">推薦度</th></tr></thead><tbody><tr><td>皇室衛隊</td><td>國王部隊上限 +60</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td>土地稅</td><td>城鎮稅收 +5%</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td>元老院</td><td>領主忠誠度 +1</td><td style="text-align:center;">⭐⭐</td></tr><tr><td>公民權</td><td>城鎮忠誠度 +1</td><td style="text-align:center;">⭐⭐</td></tr></tbody></table><h3 id="_3-2-避免的政策" tabindex="-1">3.2 避免的政策 <a class="header-anchor" href="#_3-2-避免的政策" aria-label="Permalink to &quot;3.2 避免的政策&quot;">​</a></h3><table tabindex="0"><thead><tr><th>政策</th><th>原因</th></tr></thead><tbody><tr><td>農奴制</td><td>領主扣關係，民眾忠誠降</td></tr><tr><td>狩獵權</td><td>好處有限，領主不一定支持</td></tr></tbody></table><blockquote><p>每次提政策前先看支持率。低於 50% 的不要硬推，會被否決還扣關係。</p></blockquote><hr><h2 id="四、領主關係管理" tabindex="-1">四、領主關係管理 <a class="header-anchor" href="#四、領主關係管理" aria-label="Permalink to &quot;四、領主關係管理&quot;">​</a></h2><h3 id="_4-1-關係值影響什麼" tabindex="-1">4.1 關係值影響什麼 <a class="header-anchor" href="#_4-1-關係值影響什麼" aria-label="Permalink to &quot;4.1 關係值影響什麼&quot;">​</a></h3><ul><li>關係高 → 投票支持你 → 帶兵跟你打仗</li><li>關係低 → 投票反對你 → 可能叛變</li></ul><h3 id="_4-2-怎麼提升關係" tabindex="-1">4.2 怎麼提升關係 <a class="header-anchor" href="#_4-2-怎麼提升關係" aria-label="Permalink to &quot;4.2 怎麼提升關係&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>效果</th></tr></thead><tbody><tr><td>分封地給他們</td><td>大幅提升</td></tr><tr><td>支持他們的政策提案</td><td>小幅提升</td></tr><tr><td>一起打仗</td><td>慢慢累積</td></tr><tr><td>送禮物（Mod）</td><td>裝 Diplomacy MOD 後可用</td></tr></tbody></table><h3 id="_4-3-叛變徵兆" tabindex="-1">4.3 叛變徵兆 <a class="header-anchor" href="#_4-3-叛變徵兆" aria-label="Permalink to &quot;4.3 叛變徵兆&quot;">​</a></h3><ul><li>關係值持續下降</li><li>封地太少卻一直要求更多</li><li>經常投票反對你</li><li>不帶兵參加軍團</li></ul><blockquote><p>發現這些徵兆 → 立刻給封地或提升關係，不要等到叛變。</p></blockquote><hr><h2 id="五、經濟管理" tabindex="-1">五、經濟管理 <a class="header-anchor" href="#五、經濟管理" aria-label="Permalink to &quot;五、經濟管理&quot;">​</a></h2><h3 id="_5-1-王國收入" tabindex="-1">5.1 王國收入 <a class="header-anchor" href="#_5-1-王國收入" aria-label="Permalink to &quot;5.1 王國收入&quot;">​</a></h3><table tabindex="0"><thead><tr><th>來源</th><th>說明</th></tr></thead><tbody><tr><td>個人封地稅收</td><td>你直轄的城鎮</td></tr><tr><td>工廠/商隊</td><td>個人被動收入</td></tr><tr><td>戰爭賠款</td><td>停戰時對方付的錢</td></tr><tr><td>貢金</td><td>附庸國付的錢</td></tr></tbody></table><h3 id="_5-2-王國支出" tabindex="-1">5.2 王國支出 <a class="header-anchor" href="#_5-2-王國支出" aria-label="Permalink to &quot;5.2 王國支出&quot;">​</a></h3><table tabindex="0"><thead><tr><th>支出</th><th>說明</th></tr></thead><tbody><tr><td>部隊薪水</td><td>最大的支出</td></tr><tr><td>駐軍薪水</td><td>城鎮/城堡的守軍</td></tr><tr><td>貢金</td><td>你付給其他國家的</td></tr></tbody></table><blockquote><p>💡 永遠確保日收入 &gt; 日支出。赤字持續太久 = 兵跑光。</p></blockquote><hr><h2 id="六、進階管理技巧" tabindex="-1">六、進階管理技巧 <a class="header-anchor" href="#六、進階管理技巧" aria-label="Permalink to &quot;六、進階管理技巧&quot;">​</a></h2><h3 id="_6-1-集中力量打一國" tabindex="-1">6.1 集中力量打一國 <a class="header-anchor" href="#_6-1-集中力量打一國" aria-label="Permalink to &quot;6.1 集中力量打一國&quot;">​</a></h3><p>不要同時跟多國開戰。一次打一個，打完停戰再打下一個。</p><h3 id="_6-2-用軍團集結" tabindex="-1">6.2 用軍團集結 <a class="header-anchor" href="#_6-2-用軍團集結" aria-label="Permalink to &quot;6.2 用軍團集結&quot;">​</a></h3><p>創建軍團（花影響力）→ 呼叫領主帶兵加入 → 集中兵力攻城。軍團戰力遠大於各自為戰。</p><h3 id="_6-3-收附庸而非占領" tabindex="-1">6.3 收附庸而非占領 <a class="header-anchor" href="#_6-3-收附庸而非占領" aria-label="Permalink to &quot;6.3 收附庸而非占領&quot;">​</a></h3><p>有些小國家可以威脅附庸而不需要完全征服。附庸國會付貢金，不佔你的封地。</p><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./kingdom-building.html">騎砍2 | 自立為王</a></li><li><a href="./diplomacy-guide.html">騎砍2 | 外交系統詳解</a></li><li><a href="./lord-loyalty.html">騎砍2 | 領主忠誠與叛變預防</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',55)])])}const m=a(l,[["render",h]]);export{u as __pageData,m as default};
